import { Component, inject, OnInit, OnDestroy, computed, signal, effect, untracked, ChangeDetectionStrategy } from '@angular/core';
import { ScheduleService } from '../../services/schedule.service';
import { ConfigurationService } from '../../services/configuration.service';
import { PreferencesService } from '../../services/preferences.service';
import { ScheduleAppointment, COLUMN_DEFINITIONS, ColumnDefinition } from '../../models/schedule.model';

@Component({
  selector: 'app-schedule-list',
  standalone: true,
  templateUrl: './schedule-list.html',
  styleUrl: './schedule-list.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ScheduleListComponent implements OnInit, OnDestroy {
  readonly scheduleService = inject(ScheduleService);
  private readonly configService = inject(ConfigurationService);
  readonly preferencesService = inject(PreferencesService);

  readonly dragColumnIndex = signal<number | null>(null);
  readonly dropTargetIndex = signal<number | null>(null);

  readonly orderedColumns = computed((): ColumnDefinition[] => {
    const order = this.preferencesService.columnOrder();
    return order
      .map(key => COLUMN_DEFINITIONS.find(c => c.key === key))
      .filter((c): c is ColumnDefinition => c !== undefined);
  });

  readonly sortedAppointments = computed((): ScheduleAppointment[] => {
    const appointments = this.scheduleService.filteredAppointments();
    const sortCol = this.preferencesService.sortColumn();
    const sortDir = this.preferencesService.sortDirection();

    if (!sortCol || !sortDir) return appointments;

    return [...appointments].sort((a, b) => {
      const aVal = (a as any)[sortCol] ?? '';
      const bVal = (b as any)[sortCol] ?? '';
      const cmp = String(aVal).localeCompare(String(bVal));
      return sortDir === 'asc' ? cmp : -cmp;
    });
  });

  private initialLoadDone = false;

  private readonly configEffect = effect(() => {
    const loaded = this.configService.isLoaded();
    if (loaded && !this.initialLoadDone) {
      this.initialLoadDone = true;
      untracked(() => {
        this.scheduleService.loadAppointments();
        this.scheduleService.startAutoRefresh();
      });
    }
  });

  ngOnInit(): void {
    // Initial load handled by configEffect when config is ready
  }

  ngOnDestroy(): void {
    this.scheduleService.stopAutoRefresh();
  }

  onPhysicianChange(event: Event): void {
    const value = (event.target as HTMLSelectElement).value;
    this.preferencesService.setPhysicianFilter(value ? Number(value) : null);
  }

  onSortColumn(columnKey: string): void {
    const currentCol = this.preferencesService.sortColumn();
    const currentDir = this.preferencesService.sortDirection();

    if (currentCol !== columnKey) {
      this.preferencesService.setSortColumn(columnKey, 'asc');
    } else if (currentDir === 'asc') {
      this.preferencesService.setSortColumn(columnKey, 'desc');
    } else {
      this.preferencesService.setSortColumn(null, null);
    }
  }

  getSortIndicator(columnKey: string): string {
    if (this.preferencesService.sortColumn() !== columnKey) return '';
    return this.preferencesService.sortDirection() === 'asc' ? ' \u25B2' : ' \u25BC';
  }

  getStatusClass(status: string): string {
    const s = status?.toLowerCase() ?? '';
    if (s.includes('confirm')) return 'status-confirmed';
    if (s.includes('checked') || s.includes('check')) return 'status-checked-in';
    if (s.includes('pending')) return 'status-pending';
    if (s.includes('cancel')) return 'status-cancelled';
    if (s.includes('no show') || s.includes('noshow')) return 'status-no-show';
    return 'status-unknown';
  }

  getCellValue(appointment: ScheduleAppointment, key: string): string {
    return (appointment as any)[key] ?? '\u2014';
  }

  trackBySchEventId(_index: number, appointment: ScheduleAppointment): number {
    return appointment.sch_event_id;
  }

  onDragStart(event: DragEvent, index: number): void {
    this.dragColumnIndex.set(index);
    if (event.dataTransfer) {
      event.dataTransfer.effectAllowed = 'move';
    }
  }

  onDragOver(event: DragEvent, index: number): void {
    event.preventDefault();
    this.dropTargetIndex.set(index);
  }

  onDragLeave(): void {
    this.dropTargetIndex.set(null);
  }

  onDrop(event: DragEvent, dropIndex: number): void {
    event.preventDefault();
    const dragIndex = this.dragColumnIndex();
    if (dragIndex === null || dragIndex === dropIndex) return;

    const order = [...this.preferencesService.columnOrder()];
    const [moved] = order.splice(dragIndex, 1);
    order.splice(dropIndex, 0, moved);
    this.preferencesService.setColumnOrder(order);

    this.dragColumnIndex.set(null);
    this.dropTargetIndex.set(null);
  }

  onDragEnd(): void {
    this.dragColumnIndex.set(null);
    this.dropTargetIndex.set(null);
  }
}
